const K="ch";
function c():vscode.WorkspaceConfiguration{return vscode.workspace.getConfiguration(K);}
function getP():Profile[]{return c().get<Profile[]>("profiles",[]);}
function setP(p:Profile[]){c().update("profiles",p,vscode.ConfigurationTarget.Global);}
function gid():string{return Date.now().toString(36)+Math.random().toString(36).slice(2,6);}
function defId():string{const d=c().get<string>("def","");if(d&&getP().some(p=>p.id===d))return d;return"";}
function findP(id:string):Profile|undefined{return getP().find(x=>x.id===id);}
function realDef():Profile|undefined{const d=defId();if(d)return findP(d);return getP()[0];}

