function addRecent(path:string){
  const all=c().get<RecentProject[]>("recent",[]);const name=path.split("\\").pop()||path;
  const existing=all.findIndex(r=>r.path===path);if(existing>=0)all.splice(existing,1);
  all.unshift({path,name,time:Date.now()});c().update("recent",all.slice(0,20),vscode.ConfigurationTarget.Global);
}
function getRecent():RecentProject[]{return c().get<RecentProject[]>("recent",[]);}
function clearRecent(){c().update("recent",[],vscode.ConfigurationTarget.Global);}
