async function checkOmniRoute():Promise<boolean>{
  try{const r=await fetch("http://localhost:20128/v1");if(r.ok||r.status===401||r.status===404)return true}catch{}
  return false;
}
let omniRouteTerminal:vscode.Terminal|undefined;
async function ensureOmniRoute(){
  if(!c().get<boolean>("omniRoute",false))return;
  const ok=await checkOmniRoute();if(ok)return;
  vscode.window.setStatusBarMessage(`$(sync) ${t("omniRouteStart")}`,3000);
  omniRouteTerminal=vscode.window.createTerminal({name:"omniRoute",iconPath:new vscode.ThemeIcon("globe"),location:undefined,hideFromUser:true});
  omniRouteTerminal.sendText("omnitouch");
  const d=vscode.window.onDidCloseTerminal(t=>{if(t===omniRouteTerminal){omniRouteTerminal=undefined;d.dispose();}});
}

