export function activate(ctx:vscode.ExtensionContext){
  const panel=new Panel(ctx);
  ctx.subscriptions.push(vscode.window.registerWebviewViewProvider(Panel.vt,panel,{webviewOptions:{retainContextWhenHidden:true}}));

  // Track workspace changes for recent projects
  ctx.subscriptions.push(vscode.workspace.onDidChangeWorkspaceFolders(e=>{
    e.added.forEach(f=>addRecent(f.uri.fsPath));
  }));
  if(vscode.workspace.workspaceFolders?.[0])addRecent(vscode.workspace.workspaceFolders[0].uri.fsPath);

  // Commands
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.run",()=>{const p=realDef();if(p)runP(p);}));
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.oc",()=>openCLI(ctx)));
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.desktop",()=>openDesk(ctx)));
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.addFile",addFile));
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.saveSession",()=>saveSession()));
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.restoreSession",async()=>{const ss=listSessions();if(!ss.length)return;const p=await vscode.window.showQuickPick(ss.map(s=>({label:s.name,description:`${s.profiles.length} terminals`,id:s.id})));if(p){const s=ss.find(x=>x.id===p.id);if(s)restoreSession(s);}}));
  ctx.subscriptions.push(vscode.commands.registerCommand("ch.settings",()=>vscode.commands.executeCommand("workbench.action.openSettings",K)));

  const sb=vscode.window.createStatusBarItem(vscode.StatusBarAlignment.Right,100);sb.show();ctx.subscriptions.push(sb);
  const upd=()=>{
    const n=vscode.window.terminals.filter(t=>t.name.includes("CodeHub")||t.name==="opencode"||t.name==="oc-srv"||t.name==="omniRoute").length;
    const def=realDef();
    sb.text=n>0?`$(terminal) CodeHub (${n})`:"$(terminal) CodeHub";
    sb.tooltip=def?`$(terminal) ${def.name}: ${bC(def)}`:`$(terminal) ${t("statusTip")}`;
    sb.command="ch.run";
  };
  upd();
  ctx.subscriptions.push(vscode.window.onDidOpenTerminal(upd));
  ctx.subscriptions.push(vscode.window.onDidCloseTerminal(()=>{upd();panel.render();}));
  ctx.subscriptions.push(vscode.workspace.onDidChangeConfiguration(e=>{if(e.affectsConfiguration(K)){cIC();panel.render();}}));

  // Startup
  const delay=c().get<number>("startupDelay",1200);
  if(c().get<string>("startupMode","default")!=="none"){
    setTimeout(async()=>{
      await ensureOmniRoute();
      const p=realDef();if(p)runP(p);
    },delay);
  }
}

export function deactivate(){terms.clear();srvP.clear();}
